checker_dsl:
EXISTS (`taint flow path P`) {
  AND {
    EXISTS (`source node S`) {
      (`S is an ActiveThreatModelSource`)
    },
    EXISTS (`sink node K`) {
      (`K is a JexlEvaluationSink`)
    },
    (`P is a taint flow path from S to K`),
    EXISTS (`additional taint step configuration C`) {
      AND {
        (`C implements DataFlow::ConfigSig`),
        (`C defines isSource as S being an ActiveThreatModelSource`),
        (`C defines isSink as K being a JexlEvaluationSink`),
        (`C defines isAdditionalFlowStep with three possible taint propagation cases`),
        EXISTS (`additional taint step case`) {
          OR {
            AND {
              EXISTS (`method call MC1`, `method M1`) {
                AND {
                  (`M1 is the method of MC1`),
                  (`MC1 is a call to JexlEngine.createScript`),
                  (`MC1's qualifier is not a safe engine`),
                  (`MC1's first argument is a String`),
                  (`the first argument node taints the MC1 node`)
                }
              }
            },
            AND {
              EXISTS (`method call MC2`, `method M2`) {
                AND {
                  (`M2 is the method of MC2`),
                  (`MC2 is a call to JexlEngine.createExpression or JxltEngine.createExpression or UnifiedJexl.parse`),
                  (`MC2's qualifier is not a safe engine`),
                  (`MC2 has a String argument`),
                  (`the String argument node taints the MC2 node`)
                }
              }
            },
            AND {
              EXISTS (`method call MC3`, `method M3`, `type T`) {
                AND {
                  (`M3 is the method of MC3`),
                  (`MC3 is a call to JxltEngine.createTemplate or UnifiedJexl.createTemplate`),
                  (`MC3's qualifier is not a safe engine`),
                  (`MC3's first or second argument is a String or Reader`),
                  (`T is the type of the argument`),
                  (`T is String or Reader`),
                  (`the argument node taints the MC3 node`)
                }
              }
            }
          }
        },
        (`safe engine check predicate defines two ways an engine is safe`),
        OR {
          AND {
            EXISTS (`method call MA`, `method M`) {
              AND {
                (`M is the method of MA`),
                (`M is declared in JexlBuilder`),
                (`M has name "uberspect" or "sandbox"`),
                (`M returns JexlBuilder`),
                (`the safe engine flows from MA or MA's qualifier`)
              }
            }
          },
          AND {
            EXISTS (`constructor call CC`) {
              AND {
                (`CC constructs a JexlEngine`),
                (`CC's first argument type is JexlUberspect`),
                (`the safe engine flows from CC`)
              }
            }
          }
        }
      }
    }
  }
}
